#include <iostream>
#include <optional>

enum Predicate {
  ICMP_EQ = 32,
  ICMP_NE = 33,
  ICMP_UGT = 34,
  ICMP_UGE = 35,
  ICMP_ULT = 36,
  ICMP_ULE = 37,
  ICMP_SGT = 38,
  ICMP_SGE = 39,
  ICMP_SLT = 40,
  ICMP_SLE = 41
};

class CmpPredicate {
  Predicate Pred;
  bool HasSameSign;

public:
  CmpPredicate(Predicate Pred, bool HasSameSign = false)
      : Pred(Pred), HasSameSign(HasSameSign) {}

  operator Predicate() const { return Pred; }
  bool hasSameSign() const { return HasSameSign; }
};

Predicate getFlippedSignednessPredicate(Predicate pred) {
  // Simple implementation for testing
  switch (pred) {
    case ICMP_ULT: return ICMP_SLT;
    case ICMP_SLT: return ICMP_ULT;
    case ICMP_ULE: return ICMP_SLE;
    case ICMP_SLE: return ICMP_ULE;
    case ICMP_UGT: return ICMP_SGT;
    case ICMP_SGT: return ICMP_UGT;
    case ICMP_UGE: return ICMP_SGE;
    case ICMP_SGE: return ICMP_UGE;
    default: return pred;
  }
}

int main() {
  // Test case: LPred has samesign, RPred doesn't
  CmpPredicate LPred(ICMP_ULT, true);  // samesign ult
  CmpPredicate RPred(ICMP_SLT, false); // slt (no samesign)

  std::cout << "LPred.hasSameSign(): " << LPred.hasSameSign() << std::endl;
  std::cout << "RPred.hasSameSign(): " << RPred.hasSameSign() << std::endl;
  std::cout << "LPred.hasSameSign() ^ RPred.hasSameSign(): " 
