    std::cout << "After transformation:" << std::endl;
    std::cout << "LPred: " << static_cast<Predicate>(LPred) << std::endl;
    std::cout << "RPred: " << static_cast<Predicate>(RPred) << std::endl;
  }

  return 0;
}
